const input = $input.first().json;
const body = input.body ?? input;
const env = typeof $env !== 'undefined' ? $env : (globalThis.process?.env ?? {});
const telegramMessage = body.message ?? body.edited_message ?? null;
const telegramChatId = telegramMessage?.chat?.id !== undefined ? String(telegramMessage.chat.id) : null;
const telegramText = typeof telegramMessage?.text === 'string' ? telegramMessage.text.trim() : '';
const allowedTelegramChatId = String(env.TELEGRAM_CHAT_ID || '').trim();
if (telegramChatId && allowedTelegramChatId && telegramChatId !== allowedTelegramChatId) {
  throw new Error('Unauthorized Telegram chat id: ' + telegramChatId);
}
function stripTelegramCommand(text) {
  return text.replace(/^\/(?:ask|answer|query)(?:@\w+)?\s*/i, '').trim();
}
const bodyQuestion = typeof body.question === 'string' ? body.question.trim() : '';
const question = telegramText
  ? stripTelegramCommand(telegramText)
  : bodyQuestion || 'What should I know from the current wiki state?';
if (telegramText && !question) {
  throw new Error('Telegram message did not include a question after the command');
}
const limit = Number.isFinite(Number(body.limit)) && Number(body.limit) > 0 ? Number(body.limit) : 8;
return [{
  json: {
    question,
    limit,
    telegram_chat_id: telegramChatId,
    telegram_message_id: telegramMessage?.message_id ?? null,
    telegram_update_id: body.update_id ?? null
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('search.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const payload = {
  question: $node["Prepare Query"].json.question,
  retrieval: $input.first().json
};
return [{
  json: {
    payload,
    payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('answer-context.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const packet = $input.first().json;
const env = typeof $env !== 'undefined' ? $env : (globalThis.process?.env ?? {});
const baseUrl = (env.OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1').replace(/\/+$/, '');
const model = (env.OPENROUTER_MODEL || '').trim();
const temperature = Number.isFinite(Number(env.OPENROUTER_ANSWER_TEMPERATURE))
  ? Number(env.OPENROUTER_ANSWER_TEMPERATURE)
  : 0.2;
const contextDocs = Array.isArray(packet.context_docs) ? packet.context_docs : [];
const requestBody = {
  ...(model ? { model } : {}),
  stream: false,
  temperature,
  messages: [
    {
      role: 'system',
      content: [
        'You answer questions using only the provided markdown wiki context.',
        'If the context is insufficient, say what is missing instead of inventing facts.',
        'Do not mutate the wiki and do not claim to have updated files.',
        'Return concise markdown suitable for an answer artifact.'
      ].join(' ')
    },
    {
      role: 'user',
      content: JSON.stringify({
        question: packet.question,
        evidence_used: packet.answer_record?.evidence_used ?? [],
        context_docs: contextDocs.map((doc) => ({
          path: doc.path,
          title: doc.title,
          doc_type: doc.doc_type,
          body: doc.body
        }))
      }, null, 2)
    }
  ]
};
return [{
  json: {
    ...packet,
    openrouter_url: baseUrl + '/chat/completions',
    openrouter_request: requestBody
  }
}];

const raw = $input.first().json;
const response = raw.body ?? raw;
const choice = Array.isArray(response.choices) ? response.choices[0] : undefined;
const content = choice?.message?.content ?? choice?.text;
const answer = Array.isArray(content)
  ? content.map((part) => typeof part === 'string' ? part : part?.text ?? '').join('').trim()
  : typeof content === 'string'
    ? content.trim()
    : '';
if (!answer) {
  throw new Error('OpenRouter answer response did not include choices[0].message.content');
}
const packet = $node['Build OpenRouter Answer Request'].json;
return [{
  json: {
    ...packet,
    answer,
    openrouter_answer_meta: {
      id: response.id ?? null,
      model: response.model ?? null,
      usage: response.usage ?? null,
      finish_reason: choice?.finish_reason ?? null
    }
  }
}];

const payload = {
  answer_record: $json.answer_record,
  answer: $json.answer
};
return [{
  json: {
    ...$json,
    answer_record_payload: payload,
    answer_record_payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('answer-record.ts returned empty stdout');
}
const parsed = JSON.parse(stdout);
return [{
  json: {
    ...$node['Build Answer Record Payload'].json,
    answer_record_result: parsed,
    answer_record: parsed.record
  }
}];

const packet = $json;
const env = typeof $env !== 'undefined' ? $env : (globalThis.process?.env ?? {});
const baseUrl = (env.OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1').replace(/\/+$/, '');
const model = (env.OPENROUTER_MODEL || '').trim();
const contextDocs = Array.isArray(packet.context_docs) ? packet.context_docs : [];
const requestBody = {
  ...(model ? { model } : {}),
  stream: false,
  temperature: 0,
  messages: [
    {
      role: 'system',
      content: [
        'You produce only valid JSON matching the Feedback Record contract.',
        'Valid decision values are none, output_only, and propagate.',
        'Use propagate only for small reusable wiki changes grounded in the evidence_used paths.',
        'Every candidate item must include item_id, target_note, change_type, novelty, source_support, proposed_content, and outcome.',
        'Use outcome applied only for changes you recommend a human approve; otherwise use deferred or rejected.',
        'Do not copy the whole answer into the wiki.'
      ].join(' ')
    },
    {
      role: 'user',
      content: JSON.stringify({
        output_id: packet.answer_record.output_id,
        answer_record: packet.answer_record,
        answer: packet.answer,
        source_refs: packet.answer_record.evidence_used ?? [],
        context_docs: contextDocs.map((doc) => ({
          path: doc.path,
          title: doc.title,
          doc_type: doc.doc_type,
          body: doc.body
        })),
        required_json_shape: {
          output_id: packet.answer_record.output_id,
          decision: 'none|output_only|propagate',
          reason: 'short reason',
          source_refs: packet.answer_record.evidence_used ?? [],
          candidate_items: [],
          affected_notes: []
        }
      }, null, 2)
    }
  ]
};
return [{
  json: {
    ...packet,
    openrouter_url: baseUrl + '/chat/completions',
    openrouter_request: requestBody
  }
}];

function extractJson(text) {
  const stripped = text.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  try {
    return JSON.parse(stripped);
  } catch (error) {
    const match = stripped.match(/\{[\s\S]*\}/);
    if (!match) throw error;
    return JSON.parse(match[0]);
  }
}
const raw = $input.first().json;
const response = raw.body ?? raw;
const choice = Array.isArray(response.choices) ? response.choices[0] : undefined;
const content = choice?.message?.content ?? choice?.text;
const text = Array.isArray(content)
  ? content.map((part) => typeof part === 'string' ? part : part?.text ?? '').join('').trim()
  : typeof content === 'string'
    ? content.trim()
    : '';
if (!text) {
  throw new Error('OpenRouter feedback response did not include JSON content');
}
const proposedFeedback = extractJson(text);
if (!proposedFeedback.output_id) {
  proposedFeedback.output_id = $node['Parse Answer Record'].json.answer_record.output_id;
}
if (!Array.isArray(proposedFeedback.source_refs)) {
  proposedFeedback.source_refs = $node['Parse Answer Record'].json.answer_record.evidence_used ?? [];
}
if (!Array.isArray(proposedFeedback.candidate_items)) {
  proposedFeedback.candidate_items = [];
}
if (!Array.isArray(proposedFeedback.affected_notes)) {
  proposedFeedback.affected_notes = proposedFeedback.candidate_items
    .filter((item) => item.outcome === 'applied')
    .map((item) => item.target_note)
    .filter(Boolean);
}
const packet = $node['Build OpenRouter Feedback Request'].json;
return [{
  json: {
    ...packet,
    proposed_feedback: proposedFeedback,
    proposed_feedback_payload_b64: Buffer.from(JSON.stringify(proposedFeedback), 'utf8').toString('base64'),
    openrouter_feedback_meta: {
      id: response.id ?? null,
      model: response.model ?? null,
      usage: response.usage ?? null,
      finish_reason: choice?.finish_reason ?? null
    }
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('feedback-record.ts --no-write returned empty stdout');
}
const validation = JSON.parse(stdout);
return [{
  json: {
    ...$node['Parse Proposed Feedback'].json,
    feedback_validation: validation
  }
}];

const feedback = $json.feedback_validation.record;
return [{
  json: {
    status: 'answer_recorded_feedback_proposed',
    question: $json.question,
    answer: $json.answer,
    answer_record: $json.answer_record,
    output_path: $json.answer_record_result.output_path,
    proposed_feedback: feedback,
    approval_required: feedback.decision === 'propagate',
    apply_feedback_workflow: 'KB - Apply Feedback',
    approval_payload: {
      approved: true,
      feedback
    },
    openrouter_answer_meta: $json.openrouter_answer_meta,
    openrouter_feedback_meta: $json.openrouter_feedback_meta
  }
}];

function truncate(value, maxLength) {
  const text = String(value ?? '');
  return text.length > maxLength ? text.slice(0, maxLength - 3) + '...' : text;
}
function compactLines(values) {
  return values.filter((value) => typeof value === 'string' && value.trim()).join(String.fromCharCode(10));
}
const env = typeof $env !== 'undefined' ? $env : (globalThis.process?.env ?? {});
const chatId = String($json.telegram_chat_id ?? env.TELEGRAM_CHAT_ID ?? '').trim();
const token = String(env.TELEGRAM_BOT_TOKEN ?? '').trim();
const missingConfig = [];
if (!token) missingConfig.push('TELEGRAM_BOT_TOKEN');
if (!chatId) missingConfig.push('telegram_chat_id or TELEGRAM_CHAT_ID');
const evidence = Array.isArray($json.answer_record?.evidence_used) ? $json.answer_record.evidence_used : [];
const text = compactLines([
  'KB answer completed',
  'Question: ' + truncate($json.question, 500),
  'Answer:',
  truncate($json.answer, 2600),
  $json.output_path ? 'Output: ' + $json.output_path : '',
  evidence.length ? 'Evidence: ' + evidence.slice(0, 6).join(', ') : '',
  'Feedback decision: ' + ($json.proposed_feedback?.decision ?? 'unknown'),
  $json.approval_required ? 'Feedback approval required: yes' : 'Feedback approval required: no'
]);
return [{
  json: {
    ...$json,
    telegram_enabled: missingConfig.length === 0,
    telegram_skip_reason: missingConfig.length ? 'Missing Telegram runtime configuration: ' + missingConfig.join(', ') : null,
    telegram_bot_token: token,
    telegram_answer_message: {
      chat_id: chatId,
      text,
      disable_web_page_preview: true
    }
  }
}];

const fallback = $node['Build Telegram Answer Log'].json;
const telegramResponse = $json.ok !== undefined ? $json : null;
return [{
  json: {
    ...fallback,
    telegram_answer_log_sent: Boolean(telegramResponse?.ok),
    telegram_answer_log_result: telegramResponse
  }
}];
